// Generate the two listing page URLs
return [
  { json: { category: 'editors_picks', url: 'https://www.tradingview.com/scripts/editors-picks/' } },
  { json: { category: 'most_popular', url: 'https://www.tradingview.com/scripts/' } }
];

// Parse listing pages and extract script card data
const results = [];
const seen = new Set();

for (const item of $input.all()) {
  const html = item.json.data || item.json.body || '';
  const category = item.json.category || 'unknown';

  if (!html || html.length < 1000) {
    console.log('[WARN] Empty or short response for ' + category);
    continue;
  }

  // Extract article cards using the ideaCard pattern
  // Each card has: title link, description, image, author
  const cardRegex = /<article[^>]*class="[^"]*ideaCard[^"]*"[^>]*>(.*?)<\/article>/gs;
  let match;
  let count = 0;

  while ((match = cardRegex.exec(html)) !== null && count < 20) {
    const card = match[1];

    // Extract title
    const titleMatch = card.match(/data-qa-id="ui-lib-card-link-title"[^>]*>([^<]+)/);
    const title = titleMatch ? titleMatch[1].trim() : '';
    if (!title) continue;

    // Extract script URL (first non-fragment script URL)
    const urlMatch = card.match(/href="(https:\/\/www\.tradingview\.com\/script\/[^"#]+)"/);
    const scriptUrl = urlMatch ? urlMatch[1] : '';
    if (!scriptUrl) continue;

    // Dedup by URL
    if (seen.has(scriptUrl)) continue;
    seen.add(scriptUrl);

    // Extract script ID from URL (e.g., Ft4zyO1F from /script/Ft4zyO1F-Name/)
    const idMatch = scriptUrl.match(/\/script\/([A-Za-z0-9]+)/);
    const scriptId = idMatch ? idMatch[1] : '';

    // Extract author from /u/username/ pattern in card
    const authorMatch = card.match(/\/u\/([A-Za-z0-9_-]+)/);
    // Fallback: extract from broader pattern around card
    const author = authorMatch ? authorMatch[1] : '';

    // Extract description (from line-clamp content)
    const descMatch = card.match(/line-clamp-content-[^"]*"[^>]*>(.*?)<\/span>/s);
    let description = '';
    if (descMatch) {
      description = descMatch[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim().substring(0, 500);
    }

    // Extract chart preview image
    const imgMatch = card.match(/src="(https:\/\/s3\.tradingview\.com\/[^"]+)"/);
    const screenshotUrl = imgMatch ? imgMatch[1] : null;

    results.push({
      json: {
        title,
        author,
        description,
        script_url: scriptUrl,
        script_id: scriptId,
        screenshot_url: screenshotUrl,
        category,
        scraped_at: new Date().toISOString(),
        pine_code: '',  // Will be filled by detail fetch
        pine_pub_id: '' // Will be filled by detail fetch
      }
    });

    count++;
  }

  console.log('[PARSE] ' + category + ': ' + count + ' scripts extracted from ' + html.length + ' chars');
}

// Load existing dedup state
const state = $getWorkflowStaticData('global');
if (!state.seenUrls) state.seenUrls = {};

// Filter out already-seen URLs (dedup across runs)
const newResults = [];
for (const r of results) {
  const url = r.json.script_url;
  if (state.seenUrls[url]) {
    console.log('[DEDUP] Skipping already-seen: ' + r.json.title);
    continue;
  }
  state.seenUrls[url] = new Date().toISOString();
  newResults.push(r);
}

// Prune dedup state older than 30 days
const thirtyDaysAgo = new Date(Date.now() - 30 * 86400000).toISOString();
for (const [url, date] of Object.entries(state.seenUrls)) {
  if (date < thirtyDaysAgo) delete state.seenUrls[url];
}

console.log('[RESULT] ' + newResults.length + ' new scripts (filtered from ' + results.length + ' total)');

if (newResults.length === 0) {
  // Return a sentinel so workflow doesn't error on empty
  return [{ json: { _empty: true, message: 'No new scripts found this run' } }];
}

return newResults;

// Extract Pine script metadata from individual script pages
// The SSR init-data JSON contains script access type and PUB ID
const results = [];

for (const item of $input.all()) {
  const html = item.json.data || item.json.body || '';
  const original = item.json;

  let pinePubId = '';
  let scriptAccess = 'UNKNOWN';
  let scriptType = '';
  let author = original.author || '';
  let description = original.description || '';
  let screenshotUrl = original.screenshot_url || null;

  try {
    // Extract init-data JSON blocks
    const initRegex = /<script type="application\/prs\.init-data\+json">(.*?)<\/script>/gs;
    let block;

    while ((block = initRegex.exec(html)) !== null) {
      try {
        const data = JSON.parse(block[1]);

        // Search for ssrIdeaData in nested structure
        for (const [key, val] of Object.entries(data)) {
          if (val && typeof val === 'object' && val.ssrIdeaData) {
            const idea = val.ssrIdeaData;

            // Get script PUB ID
            if (idea.script && idea.script.script_id_part) {
              pinePubId = idea.script.script_id_part;
            }

            // Get access type: 1=open, 2=protected/invite-only, 3=closed
            if (idea.script && idea.script.access !== undefined) {
              const access = idea.script.access;
              if (access === 1) scriptAccess = 'OPEN_SOURCE';
              else if (access === 2) scriptAccess = 'INVITE_ONLY';
              else if (access === 3 || access === 0) scriptAccess = 'PROTECTED';
              else scriptAccess = 'ACCESS_' + access;
            }

            // Script type
            if (idea.script && idea.script.script_type) {
              scriptType = idea.script.script_type;
            }

            // Better author from SSR data
            if (idea.user && idea.user.username) {
              author = idea.user.username;
            }

            // Better description
            if (idea.description && idea.description.length > description.length) {
              description = idea.description.replace(/\[b\]/g,'').replace(/\[\/b\]/g,'').replace(/\[i\]/g,'').replace(/\[\/i\]/g,'').replace(/\s+/g,' ').trim().substring(0, 1000);
            }

            // Better screenshot from SSR
            if (idea.preview_image_urls && idea.preview_image_urls.mid) {
              screenshotUrl = idea.preview_image_urls.mid;
            }

            break;
          }
        }
      } catch(e) {
        // JSON parse error in this block, try next
      }
    }

    // Fallback: check for open-source marker in HTML
    if (scriptAccess === 'UNKNOWN') {
      if (html.includes('OPEN-SOURCE SCRIPT') || html.includes('rootOpenSource')) {
        scriptAccess = 'OPEN_SOURCE';
      } else if (html.toUpperCase().includes('INVITE-ONLY')) {
        scriptAccess = 'INVITE_ONLY';
      } else if (html.toUpperCase().includes('PROTECTED SCRIPT')) {
        scriptAccess = 'PROTECTED';
      }
    }

    // Fallback author from og:title
    if (!author) {
      const ogMatch = html.match(/og:title.*?content="([^"]+)"/);
      if (ogMatch) {
        const byMatch = ogMatch[1].match(/by\s+([\w-]+)/);
        if (byMatch) author = byMatch[1];
      }
    }

  } catch(e) {
    console.log('[ERROR] Failed to parse detail page for ' + (original.title || 'unknown') + ': ' + e.message);
  }

  results.push({
    json: {
      title: original.title || '',
      author: author,
      description: description,
      script_url: original.script_url || '',
      script_id: original.script_id || '',
      screenshot_url: screenshotUrl,
      category: original.category || '',
      scraped_at: original.scraped_at || new Date().toISOString(),
      pine_pub_id: pinePubId,
      script_access: scriptAccess,
      script_type: scriptType,
      pine_code: ''  // Will be fetched next
    }
  });
}

console.log('[DETAIL] Processed ' + results.length + ' scripts. Open source: ' + results.filter(r => r.json.script_access === 'OPEN_SOURCE').length);
return results;

// Fetch Pine source code from Pine Facade API for open-source scripts
const results = [];

for (const item of $input.all()) {
  const script = { ...item.json };

  // Only fetch source for open-source scripts with a PUB ID
  if (script.script_access === 'OPEN_SOURCE' && script.pine_pub_id) {
    try {
      // Rate limit: small delay between API calls
      await new Promise(resolve => setTimeout(resolve, 500));

      const encoded = encodeURIComponent(script.pine_pub_id);
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: 'https://pine-facade.tradingview.com/pine-facade/get/' + encoded + '/last',
        headers: {
          'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64)',
          'Origin': 'https://www.tradingview.com',
          'Referer': 'https://www.tradingview.com/'
        },
        json: true
      });

      if (resp && resp.source) {
        script.pine_code = resp.source;
        console.log('[PINE] Got source for ' + script.title + ' (' + resp.source.length + ' chars)');
      } else {
        script.pine_code = 'REQUIRES_BROWSER';
        console.log('[PINE] No source in response for ' + script.title);
      }
    } catch(e) {
      script.pine_code = 'REQUIRES_BROWSER';
      console.log('[PINE] API error for ' + script.title + ': ' + e.message);
    }
  } else if (script.script_access === 'INVITE_ONLY') {
    script.pine_code = 'INVITE_ONLY';
  } else if (script.script_access === 'PROTECTED') {
    script.pine_code = 'PROTECTED';
  } else {
    script.pine_code = 'REQUIRES_BROWSER';
  }

  results.push({ json: script });
}

const withCode = results.filter(r => r.json.pine_code && !['INVITE_ONLY','PROTECTED','REQUIRES_BROWSER',''].includes(r.json.pine_code));
console.log('[PINE] ' + withCode.length + '/' + results.length + ' scripts have full Pine source code');
return results;

// Format final output and prepare for Google Sheets
const results = [];

for (let i = 0; i < $input.all().length; i++) {
  const s = $input.all()[i].json;

  // Clean up pine_code for sheets (truncate if very long)
  const pineForSheets = s.pine_code && s.pine_code.length > 50000 
    ? s.pine_code.substring(0, 50000) + '\n// [TRUNCATED — full code: ' + s.pine_code.length + ' chars]'
    : (s.pine_code || 'N/A');

  results.push({
    json: {
      index: i + 1,
      title: s.title || '',
      author: s.author || '',
      description: (s.description || '').substring(0, 2000),
      pine_code: pineForSheets,
      screenshot_url: s.screenshot_url || '',
      script_url: s.script_url || '',
      category: s.category || '',
      scraped_at: s.scraped_at || new Date().toISOString(),
      // Extra metadata (not in sheets but useful for JSON output)
      script_access: s.script_access || '',
      script_type: s.script_type || '',
      has_pine_code: s.pine_code && !['INVITE_ONLY','PROTECTED','REQUIRES_BROWSER','N/A',''].includes(s.pine_code)
    }
  });
}

console.log('[FORMAT] ' + results.length + ' scripts ready for output');
console.log('[FORMAT] With Pine code: ' + results.filter(r => r.json.has_pine_code).length);
return results;

// Filter top 3 scripts that have valid Pine code starting with //@version
const validScripts = $input.all()
  .filter(item => {
    const code = item.json.pine_code || '';
    return code.includes('//@version') && !['INVITE_ONLY','PROTECTED','REQUIRES_BROWSER'].includes(code);
  })
  .slice(0, 3);

if (validScripts.length === 0) {
  console.log('[BACKTEST] No valid Pine scripts found for backtesting');
  return [{ json: { _empty: true, message: 'No valid Pine scripts for backtesting' } }];
}

console.log('[BACKTEST] Sending ' + validScripts.length + ' scripts to backtester');
for (const s of validScripts) {
  console.log('  - ' + s.json.title + ' (' + s.json.pine_code.length + ' chars)');
}

return validScripts;

// Feed to Backtester — Pre-configured with standard settings
// TSLA, 5min, 90 days, $25K capital, 0.05% commission + 2-tick slippage
//
// NOTE: TradingView backtesting requires browser-based execution.
// This node prepares the backtest configuration for each script.
// For automated backtesting, you'd connect this to a browser automation service.

const BACKTEST_CONFIG = {
  symbol: 'TSLA',
  timeframe: '5',         // 5-minute bars
  lookback_days: 90,
  initial_capital: 25000,
  commission_pct: 0.05,
  slippage_ticks: 2,
  currency: 'USD',
  pyramiding: 0,
  default_qty_type: 'fixed',
  default_qty_value: 100
};

const results = [];

for (const item of $input.all()) {
  if (item.json._empty) continue;

  const script = item.json;
  const isStrategy = (script.pine_code || '').includes('strategy(');
  const isIndicator = (script.pine_code || '').includes('indicator(');

  results.push({
    json: {
      title: script.title,
      author: script.author,
      script_url: script.script_url,
      script_type: isStrategy ? 'strategy' : isIndicator ? 'indicator' : 'unknown',
      pine_code_length: (script.pine_code || '').length,
      pine_version: ((script.pine_code || '').match(/\/\/@version=(\d+)/) || [])[1] || 'unknown',
      backtest_config: BACKTEST_CONFIG,
      backtest_ready: isStrategy,
      backtest_note: isStrategy 
        ? 'Strategy script — ready for backtesting with config above' 
        : 'Indicator script — would need strategy wrapper for backtesting',
      scraped_at: script.scraped_at
    }
  });
}

if (results.length === 0) {
  return [{ json: { message: 'No scripts to backtest', config: BACKTEST_CONFIG } }];
}

console.log('[BACKTESTER] Prepared ' + results.length + ' scripts. Strategies: ' + results.filter(r => r.json.backtest_ready).length);
return results;
